3	import jakarta.servlet.FilterChain;
4	import jakarta.servlet.ServletException;
5	import jakarta.servlet.http.HttpServletRequest;
6	import jakarta.servlet.http.HttpServletResponse;
7	import org.springframework.beans.factory.annotation.Value;
8	import org.springframework.stereotype.Component;
9	import org.springframework.web.filter.OncePerRequestFilter;
10	
11	import java.io.IOException;
12	import java.time.Instant;
13	
14	@Component
15	public class ApiKeyAuthFilter extends OncePerRequestFilter {
16	
17	    @Value("${api.key}")
18	    private String validApiKey;
19	
20	    @Override
21	    protected void doFilterInternal(HttpServletRequest request, HttpServletResponse response, FilterChain filterChain) throws ServletException, IOException {
22	
23	        String requestApiKey = request.getHeader("x-api-key");
24	        if (requestApiKey != null && requestApiKey.equals(validApiKey)) {
25	            filterChain.doFilter(request, response);
26	            return;
27	        }
28	
29	        response.setStatus(HttpServletResponse.SC_FORBIDDEN);
30	        response.setContentType("application/json");
31	        response.getWriter().write(String.format(
32	                "{\"code\":\"FORBIDDEN\",\"message\":\"Forbidden\",\"details\":\"Missing or invalid API key\",\"path\":\"%s\",\"timestamp\":\"%s\"}",
33	                request.getRequestURI(),
34	                Instant.now()
35	        ));
36	    }
37	}
