7	import org.springframework.security.config.annotation.web.configurers.AbstractHttpConfigurer;
8	import org.springframework.security.config.http.SessionCreationPolicy;
9	import org.springframework.security.web.SecurityFilterChain;
10	import org.springframework.security.web.authentication.UsernamePasswordAuthenticationFilter;
11	import org.springframework.web.cors.CorsConfiguration;
12	import org.springframework.web.cors.CorsConfigurationSource;
13	import org.springframework.web.cors.UrlBasedCorsConfigurationSource;
14	
15	import java.util.List;
16	
17	@Configuration
18	@EnableWebSecurity
19	public class SecurityConfig {
20	
21	    private final ApiKeyAuthFilter apiKeyAuthFilter;
22	
23	    public SecurityConfig(ApiKeyAuthFilter apiKeyAuthFilter) {
24	        this.apiKeyAuthFilter = apiKeyAuthFilter;
25	    }
26	
27	    @Bean
28	    public SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
29	        http.cors(cors -> cors.configurationSource(corsConfigurationSource())).csrf(AbstractHttpConfigurer::disable).sessionManagement(session -> session.sessionCreationPolicy(SessionCreationPolicy.STATELESS)).addFilterBefore(apiKeyAuthFilter, UsernamePasswordAuthenticationFilter.class);
30	        return http.build();
31	    }
32	
33	    @Bean
34	    public CorsConfigurationSource corsConfigurationSource() {
35	        CorsConfiguration configuration = new CorsConfiguration();
36	        configuration.setAllowedOrigins(List.of("https://tallyo.us"));
37	        configuration.setAllowedMethods(List.of("GET", "POST", "PUT", "DELETE", "OPTIONS"));
38	        configuration.setAllowedHeaders(List.of("*"));
39	        configuration.setAllowCredentials(true);
40	        configuration.setMaxAge(3600L);
41	
42	        UrlBasedCorsConfigurationSource source = new UrlBasedCorsConfigurationSource();
43	        source.registerCorsConfiguration("/**", configuration);
44	        return source;
45	    }
46	}

