2	export default function getStandings(standingsJson: any): Standings[] {
3	  const conferenceGroups = getConferenceGroups(standingsJson);
4	  if (conferenceGroups.length === 0) {
5	    return [];
6	  }
7	  const standings: Standings[] = [];
8	  for (const conferenceGroup of conferenceGroups) {
9	    const parsed = parseConference(conferenceGroup);
10	    if (parsed.teams.length > 0) {
11	      standings.push(parsed);
12	    }
13	  }
14	  return standings;
15	}
