17	// eslint-disable-next-line @typescript-eslint/no-explicit-any
18	function getConferenceGroups(payload: any): any[] {
19	  const directGroups = payload?.content?.standings?.groups;
20	  if (Array.isArray(directGroups)) {
21	    return directGroups;
22	  }
23	  const conferenceChildren = payload?.children;
24	  if (Array.isArray(conferenceChildren)) {
25	    const conferences = conferenceChildren.filter((group) =>
26	      hasStandingsGroupShape(group),
27	    );
28	    if (conferences.length > 0) {
29	      return conferences;
30	    }
31	  }
32	
33	  const candidateGroups: unknown[] = [];
34	  const visited = new Set<object>();
35	
36	  // ESPN responses vary by endpoint. Walk the payload and keep only groups
37	  // that actually contain standings entries directly or in nested groups.
38	  function walk(node: unknown) {
39	    if (!node || typeof node !== "object" || visited.has(node)) {
40	      return;
41	    }
42	    visited.add(node);
43	
44	    const collections = [
45	      (node as { groups?: unknown }).groups,
46	      (node as { children?: unknown }).children,
47	      (node as { items?: unknown }).items,
48	    ];
49	    for (const collection of collections) {
50	      if (!Array.isArray(collection)) {
51	        continue;
52	      }
53	      for (const group of collection) {
54	        if (hasStandingsGroupShape(group)) {
55	          candidateGroups.push(group);
56	        }
57	      }
58	    }
59	
60	    for (const value of Object.values(node)) {
61	      if (value && typeof value === "object") {
62	        walk(value);
63	      }
64	    }
65	  }
66	
67	  walk(payload);
68	  return candidateGroups as unknown[];
69	}
70	
71	// eslint-disable-next-line @typescript-eslint/no-explicit-any
72	function hasStandingsGroupShape(group: any): boolean {
73	  if (extractStandingEntries(group).length > 0) {
74	    return true;
75	  }
76	  if (Array.isArray(group?.groups)) {
77	    return true;
78	  }
79	  if (Array.isArray(group?.children)) {
80	    return true;
81	  }
82	  if (Array.isArray(group?.items)) {
83	    return true;
84	  }
85	  return false;
86	}
87	
88	// eslint-disable-next-line @typescript-eslint/no-explicit-any
89	function extractStandingEntries(group: any): any[] {
90	  if (Array.isArray(group?.standings?.entries)) {
91	    return group.standings.entries;
92	  }
93	  if (Array.isArray(group?.entries)) {
94	    return group.entries;
95	  }
96	  return [];
97	}
