99	function collectEntriesFromGroup(
100	  group: unknown,
101	  fallbackDivisionName?: string,
102	): Array<{ entry: unknown; divisionName?: string }> {
103	  const groupObj = (group ?? {}) as {
104	    name?: string;
105	    groups?: unknown;
106	    children?: unknown;
107	    items?: unknown;
108	  };
109	  const entries = extractStandingEntries(group);
110	  const divisionName = groupObj.name ?? fallbackDivisionName;
111	  if (entries.length > 0) {
112	    return entries.map((entry) => ({ entry, divisionName }));
113	  }
114	
115	  const nested = [
116	    ...(Array.isArray(groupObj.groups) ? groupObj.groups : []),
117	    ...(Array.isArray(groupObj.children) ? groupObj.children : []),
118	    ...(Array.isArray(groupObj.items) ? groupObj.items : []),
119	  ];
120	  const collected: Array<{ entry: unknown; divisionName?: string }> = [];
121	  for (const child of nested) {
122	    collected.push(...collectEntriesFromGroup(child, divisionName));
123	  }
124	  return collected;
125	}
