128	function parseConference(conferenceGroup: any) {
129	  const conferenceGroupName = conferenceGroup?.name ?? "Standings";
130	  let conferenceTeams: Team[] = [];
131	
132	  const entries = collectEntriesFromGroup(conferenceGroup);
133	  for (const entryInfo of entries) {
134	    const parsedTeam = parseTeam(
135	      entryInfo.entry,
136	      conferenceGroupName,
137	      entryInfo.divisionName,
138	    );
139	    if (parsedTeam) {
140	      conferenceTeams.push(parsedTeam);
141	    }
142	  }
143	
144	  try {
145	    const sortedConferenceTeams = [...conferenceTeams].sort((teamA, teamB) => {
146	      const teamAIntSeed = parseInt(teamA.seed || "100");
147	      const teamBIntSeed = parseInt(teamB.seed || "100");
148	      return teamAIntSeed - teamBIntSeed;
149	    });
150	    conferenceTeams = sortedConferenceTeams;
151	  } catch (error) {
152	    console.error("error when sorting teams by seed ", error);
153	  }
154	  const conferenceStandings: Standings = {
155	    teams: conferenceTeams,
156	    groupName: conferenceGroupName,
157	  };
158	  return conferenceStandings;
159	}
