161	function parseTeam(
162	  // eslint-disable-next-line @typescript-eslint/no-explicit-any
163	  standingEntry: any,
164	  conferenceGroupName: string | undefined,
165	  divisionGroupName: string | undefined,
166	): Team | null {
167	  const teamInfo = standingEntry?.team;
