169	    return null;
170	  }
171	  const teamStats = Array.isArray(standingEntry?.stats)
172	    ? standingEntry.stats
173	    : [];
174	  const logo =
175	    teamInfo?.logos?.[0]?.href ??
176	    "https://a.espncdn.com/i/teamlogos/leagues/500/nhl.png";
177	  let team: Team = {
178	    id: String(teamInfo?.id ?? ""),
179	    name: teamInfo?.displayName ?? teamInfo?.name ?? "Unknown Team",
180	    abbreviation: teamInfo?.abbreviation ?? "",
181	    logo,
182	    location: teamInfo?.location ?? "",
183	    seed: teamInfo?.seed,
184	    division: divisionGroupName,
185	    conference: conferenceGroupName,
186	  };
187	  team = populateTeamStats(team, teamStats);
188	  if (!team.differential) {
189	    const differential =
190	      parseInt(team.pointsfor || "0") - parseInt(team.pointsagainst || "0");
191	    if (differential) {
192	      team.differential = differential.toString();
193	    }
194	  }
195	  return team;
196	}
