40	            RestClientException ex,
41	            HttpServletRequest request
42	    ) {
43	        return ResponseEntity.status(HttpStatus.BAD_GATEWAY).body(
44	                buildError(
45	                        "UPSTREAM_SERVICE_UNAVAILABLE",
