56	            HttpServletRequest request
57	    ) {
58	        return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body(
59	                buildError(
60	                        "INTERNAL_ERROR",
61	                        "An unexpected error occurred",
62	                        extractDetails(ex),
63	                        request
64	                )
65	        );
66	    }
67	
68	    private String extractDetails(Throwable throwable) {
69	        if (throwable == null) {
70	            return null;
71	        }
72	
73	        Throwable root = throwable;
74	        while (root.getCause() != null && root.getCause() != root) {
75	            root = root.getCause();
76	        }
77	
78	        String top = throwable.getMessage();
79	        String bottom = root.getMessage();
80	
81	        if (bottom == null || bottom.isBlank() || root == throwable) {
82	            return top;
83	        }
84	
85	        String rootSummary = root.getClass().getSimpleName() + ": " + bottom;
86	        return (top == null || top.isBlank()) ? rootSummary : top + " | root cause: " + rootSummary;
87	    }
88	
89	    private ApiError buildError(String code, String message, String details, HttpServletRequest request) {
90	        return ApiError.builder()
91	                .code(code)
92	                .message(message)
93	                .details(details)
94	                .path(request.getRequestURI())
95	                .timestamp(Instant.now().toString())
96	                .build();
97	    }
