357	const buildNhlSections = (standing: Standings): StandingsSection[] => {
358	  const groups = new Map<string, Team[]>();
359	  for (const team of standing.teams) {
360	    const division = team.division || "Other";
361	    if (!groups.has(division)) {
362	      groups.set(division, []);
363	    }
364	    groups.get(division)?.push(team);
365	  }
366	
367	  const divisionEntries = Array.from(groups.entries()).map(
368	    ([division, teams]) => {
369	      const sortedTeams = [...teams].sort((a, b) => {
370	        const pointsDiff = getPointsValue(b) - getPointsValue(a);
371	        if (pointsDiff !== 0) {
372	          return pointsDiff;
373	        }
374	        return getPlayoffSeedValue(a) - getPlayoffSeedValue(b);
375	      });
376	      return { division, teams: sortedTeams };
377	    },
378	  );
379	
380	  const labels = new Map<string, string>();
381	  for (const division of divisionEntries) {
382	    division.teams.slice(0, 3).forEach((team, index) => {
383	      labels.set(team.id, `Div${index + 1}`);
384	    });
385	  }
386	
387	  const wildcardCandidates = divisionEntries
388	    .flatMap((division) => division.teams.slice(3))
389	    .sort((a, b) => {
390	      const pointsDiff = getPointsValue(b) - getPointsValue(a);
391	      if (pointsDiff !== 0) {
392	        return pointsDiff;
393	      }
394	      return getPlayoffSeedValue(a) - getPlayoffSeedValue(b);
395	    });
396	  wildcardCandidates.slice(0, 2).forEach((team, index) => {
397	    labels.set(team.id, `WC${index + 1}`);
398	  });
399	
400	  return divisionEntries.map((division) => ({
401	    key: `${standing.groupName}-${division.division}`,
402	    title: division.division,
403	    rows: division.teams.map((team) => {
404	      const tag = labels.get(team.id);
405	      return {
406	        team,
407	        tag,
408	        isEmphasized: !!tag,
409	      };
410	    }),
411	  }));
412	};
