// Typed URL builders for the app's API routes. Components build request URLs
// here instead of assembling query strings inline.

export function leaguesUrl(): string {
  return "/api/leagues";
}

export function contextUrl(
  league: string,
  mode: "season" | "date",
  timezone: string,
): string {
  const params = new URLSearchParams({ league, mode, timezone });
  return `/api/context?${params}`;
}

export function gamesUrl(options: {
  league: string;
  year?: string;
  seasonType?: string;
  week?: string;
  date?: string;
  timezone?: string;
}): string {
  const params = new URLSearchParams({ league: options.league });
  if (options.year) params.set("year", options.year);
  if (options.seasonType) params.set("seasonType", options.seasonType);
  if (options.week) params.set("week", options.week);
  if (options.date) params.set("date", options.date);
  if (options.timezone) params.set("timezone", options.timezone);
  return `/api/games?${params}`;
}

export function currentGamesUrl(league: string, timezone: string): string {
  const params = new URLSearchParams({ league, timezone });
  return `/api/games/current?${params}`;
}

export function standingsUrl(league: string): string {
  const params = new URLSearchParams({ league });
  return `/api/standings?${params}`;
}

export function gameDetailsUrl(gameId: string): string {
  return `/api/games/${encodeURIComponent(gameId)}/details`;
}

// Shared helper for API routes that proxy the Spring backend. Injects the API
// key, translates timezone -> userTimeZone, and passes backend errors through
// untouched (status + body) so the client sees the real ApiError envelope.

interface ProxyOptions {
  /** Query params to forward; null/empty values are dropped. */
  params?: Record<string, string | null | undefined>;
}

export async function proxyBackend(
  path: string,
  options: ProxyOptions = {},
): Promise<Response> {
  const url = new URL(`${process.env.BACKEND_URL}${path}`);
  for (const [key, value] of Object.entries(options.params ?? {})) {
    if (value) {
      url.searchParams.set(key === "timezone" ? "userTimeZone" : key, value);
    }
  }

  const response = await fetch(url, {
    headers: {
      "x-api-key": process.env.API_KEY || "",
    },
  });

  return response;
}

export async function passthroughError(response: Response): Promise<Response> {
  const rawBody = await response.text();
  return new Response(rawBody || "Backend request failed", {
    status: response.status,
    headers: {
      "content-type": response.headers.get("content-type") || "text/plain",
    },
  });
}

export async function jsonBody<T>(
  response: Response,
  fallback: T,
): Promise<T> {
  const rawBody = await response.text();
  return rawBody ? (JSON.parse(rawBody) as T) : fallback;
}

import { NextResponse } from "next/server";
import { parseLeagueId } from "@/lib/leagues/leagueConfig";
import {
  jsonBody,
  passthroughError,
  proxyBackend,
} from "@/app/api/_lib/backendProxy";

export async function GET(request: Request) {
  const { searchParams } = new URL(request.url);
  const league = parseLeagueId(searchParams.get("league"));
  if (!league) {
    return new Response("Bad request: Invalid league", { status: 400 });
  }

  const response = await proxyBackend("/api/v1/games", {
    params: {
      league,
      year: searchParams.get("year"),
      seasonType: searchParams.get("seasonType"),
      week: searchParams.get("week"),
      date: searchParams.get("date"),
      timezone: searchParams.get("timezone"),
    },
  });

  if (!response.ok) {
    return passthroughError(response);
  }
  const body = await jsonBody<{ content?: unknown[] }>(response, {});
  return NextResponse.json(body.content ?? []);
}

