import { Game } from "@/types/api-contract";

const IN_PROGRESS_STATUSES = new Set([
  "STATUS_IN_PROGRESS",
  "STATUS_HALFTIME",
  "STATUS_END_PERIOD",
]);

const SCHEDULED_STATUS = "STATUS_SCHEDULED";
const FINAL_STATUS = "STATUS_FINAL";
const MAX_RECENTLY_STARTED_GAME_AGE_MS = 6 * 60 * 60 * 1000;

export function isScheduledGame(status?: string): boolean {
  return status === SCHEDULED_STATUS;
}

export function isFinalGame(status?: string): boolean {
  return status === FINAL_STATUS;
}

export function isInProgressGame(status?: string): boolean {
  return !!status && IN_PROGRESS_STATUSES.has(status);
}

export function shouldShowGameScore(status?: string): boolean {
  return !isScheduledGame(status);
}

export function shouldPollGameStats(status?: string): boolean {
  return !isScheduledGame(status) && !isFinalGame(status);
}

export function shouldShowScheduledOrFinalDate(status?: string): boolean {
  return isScheduledGame(status) || isFinalGame(status);
}

export function shouldShowLiveGameDetails(status?: string): boolean {
  return !isScheduledGame(status) && !isFinalGame(status);
}

export function shouldShowGameChannel(status?: string): boolean {
  return !isFinalGame(status);
}

function isRecentlyStartedGame(isoDate?: string): boolean {
  if (!isoDate) {
    return false;
  }
  const startTime = new Date(isoDate).getTime();
  if (Number.isNaN(startTime)) {
    return false;
  }
  const now = Date.now();
  return (
    now >= startTime && now - startTime <= MAX_RECENTLY_STARTED_GAME_AGE_MS
  );
}

export function isLiveDashboardGame(game: Game): boolean {
  if (isFinalGame(game.gameStatus) || !!game.winner || game.final === true) {
    return false;
  }

  if (isInProgressGame(game.gameStatus)) {
    return true;
  }

  if (isScheduledGame(game.gameStatus)) {
    return isRecentlyStartedGame(game.isoDate);
  }

  return true;
}

import { Game, Team } from "@/types/api-contract";
import { isHomeTeamLeftAligned } from "./leagues/leagueConfig";

export type GameSide = {
  team: Team;
  score?: string;
  record?: string;
  timeouts?: number;
  statSide: "homeStats" | "awayStats";
};

export function getGameSides(game: Game): { left: GameSide; right: GameSide } {
  const homeSide: GameSide = {
    team: game.homeTeam,
    score: game.homeScore,
    record: game.homeRecordAtTimeOfGame,
    timeouts: game.homeTimeouts,
    statSide: "homeStats",
  };
  const awaySide: GameSide = {
    team: game.awayTeam,
    score: game.awayScore,
    record: game.awayRecordAtTimeOfGame,
    timeouts: game.awayTimeouts,
    statSide: "awayStats",
  };

  return isHomeTeamLeftAligned(game.league)
    ? { left: homeSide, right: awaySide }
    : { left: awaySide, right: homeSide };
}

"use client";

import { useState } from "react";
import useSWR from "swr";
import { fetcher } from "@/lib/api/fetcher";
import { gameDetailsUrl } from "@/lib/api/client";
import { shouldPollGameStats } from "@/lib/gameStatus";
import { Game, GameDetails, StatLeader } from "@/types/api-contract";
import FullsizeGameCard from "./FullSizeGameCard";
import CompactGameCard from "./CompactGameCard";

interface GameProps {
  game: Game;
  isOpen: boolean;
  toggleOpenGame: () => void;
  statsToDisplay: Map<string, string>;
}

const GameCard: React.FC<GameProps> = ({
  game,
  isOpen,
  toggleOpenGame,
  statsToDisplay,
}) => {
  const [isStatsOpen, setIsStatsOpen] = useState(false);
  const [isScoringPlaysOpen, setIsScoringPlaysOpen] = useState(false);
  const [isTeamStatsOpen, setIsTeamStatsOpen] = useState(false);

  const { data: details } = useSWR<GameDetails>(
    gameDetailsUrl(game.id),
    fetcher,
    shouldPollGameStats(game.gameStatus)
      ? { refreshInterval: 10000 }
      : undefined,
  );

  const leaders = new Map<string, StatLeader>(
    (details?.leaders ?? []).map((leader) => [
      `${leader.name}-${leader.teamId}`,
      leader,
    ]),
  );

  return (
    <div
      className={`border border-gray-300 dark:border-gray-500 p-5 rounded-lg shadow-lg bg-neutral-300 dark:bg-neutral-500 transition-transform duration-300 ${
        isOpen ? "p-2" : "p-1 scale-[0.99]"
      } cursor-pointer`}
      onClick={toggleOpenGame}
    >
      {isOpen ? (
        <FullsizeGameCard
          game={game}
          leaders={leaders}
          scoringPlays={details?.scoringPlays ?? []}
          isScoringPlaysOpen={isScoringPlaysOpen}
          toggleScoringPlays={() => setIsScoringPlaysOpen((open) => !open)}
          isStatsOpen={isStatsOpen}
          toggleStats={() => setIsStatsOpen((open) => !open)}
          isTeamStatsOpen={isTeamStatsOpen}
          toggleTeamStats={() => setIsTeamStatsOpen((open) => !open)}
          statsToDisplay={statsToDisplay}
        />
      ) : (
        <CompactGameCard game={game} />
      )}
    </div>
  );
};

export default GameCard;

import { Game } from "@/types/api-contract";
import { dateFormatter } from "@/lib/format/dateFormatter";
import {
  isScheduledGame,
  shouldShowGameChannel,
  shouldShowGameScore,
  shouldShowScheduledOrFinalDate,
} from "@/lib/gameStatus";
import { getGameSides } from "@/lib/gameLayout";
import CompactTeamCard from "../TeamCard/CompactTeamCard";

interface GameCompactProps {
  game: Game;
}

const CompactGameCard: React.FC<GameCompactProps> = ({ game }) => {
  const { left, right } = getGameSides(game);

  return (
    <div>
      <CompactTeamCard
        team={left.team}
        score={left.score}
        winner={game.winner}
        possessionTeamId={game.possessionTeamId}
        showScore={shouldShowGameScore(game.gameStatus)}
      />
      <CompactTeamCard
        team={right.team}
        score={right.score}
        winner={game.winner}
        possessionTeamId={game.possessionTeamId}
        showScore={shouldShowGameScore(game.gameStatus)}
      />

      <div className="flex flex-col">
        {!isScheduledGame(game.gameStatus) && <div>{game.shortPeriod}</div>}

        {game.headline && <div>{game.headline}</div>}
        {shouldShowScheduledOrFinalDate(game.gameStatus) && (
          <div>{dateFormatter.format(new Date(game.isoDate))}</div>
        )}
        {shouldShowGameChannel(game.gameStatus) && <div>{game.channel}</div>}
      </div>
    </div>
  );
};

export default CompactGameCard;

import Link from "next/link";
import { Game, ScoringPlay, StatLeader } from "@/types/api-contract";
import FullsizeTeamCard from "../TeamCard/FullsizeTeamCard";
import CollapsableSection from "../CollapsableSection";
import { dateFormatter } from "@/lib/format/dateFormatter";
import {
  isScheduledGame,
  shouldShowGameChannel,
  shouldShowGameScore,
  shouldShowLiveGameDetails,
  shouldShowScheduledOrFinalDate,
} from "@/lib/gameStatus";
import { getGameSides } from "@/lib/gameLayout";
import {
  supportsLiveDetailsForLeague,
  supportsOddsForLeague,
} from "@/lib/leagues/leagueConfig";

interface GameProps {
  game: Game;
  leaders: Map<string, StatLeader>;
  scoringPlays: ScoringPlay[];
  isScoringPlaysOpen: boolean;
  toggleScoringPlays: () => void;
  isStatsOpen: boolean;
  toggleStats: () => void;
  isTeamStatsOpen: boolean;
  toggleTeamStats: () => void;
  statsToDisplay: Map<string, string>;
}

const FullSizeGameCard: React.FC<GameProps> = ({
  game,
  leaders,
  scoringPlays,
  isScoringPlaysOpen,
  toggleScoringPlays,
  isStatsOpen,
  toggleStats,
  isTeamStatsOpen,
  toggleTeamStats,
  statsToDisplay,
}) => {
  const { left, right } = getGameSides(game);
  const leagueSupportsLiveDetails = supportsLiveDetailsForLeague(game.league);
  const canShowLiveDetails =
    leagueSupportsLiveDetails && shouldShowLiveGameDetails(game.gameStatus);
  const canShowOdds =
    supportsOddsForLeague(game.league) && !!game.gameOdd?.spreadText;
  const renderedStatNames = new Set<string>();

  const hasTeamStats =
    !!game.stats &&
    Array.from(statsToDisplay.keys()).some(
      (stat) =>
        game.stats?.homeStats?.[stat] != null ||
        game.stats?.awayStats?.[stat] != null,
    );

  return (
    <div>
      <div className="grid grid-cols-3 place-items-center items-center justify-center p-2">
        {/* Left-side team info */}
        <FullsizeTeamCard
          team={left.team}
          score={left.score}
          possessionTeamId={game.possessionTeamId}
          league={game.league}
          gameStatus={game.gameStatus}
          homeTeam={false}
          showScore={shouldShowGameScore(game.gameStatus)}
          record={left.record}
          timeouts={left.timeouts}
          supportsLiveDetails={leagueSupportsLiveDetails}
        />

        {/* Game info */}
        <div className="flex flex-col whitespace-nowrap place-items-center items-center justify-center">
          {!isScheduledGame(game.gameStatus) && <div>{game.shortPeriod}</div>}
          {canShowLiveDetails && <div className="text-xs">{game.down}</div>}
          {canShowLiveDetails && (
            <div className="text-xs">{game.ballLocation}</div>
          )}
          {shouldShowGameChannel(game.gameStatus) && (
            <div className="text-xs">{game.channel}</div>
          )}
        </div>
        {/* Right-side team info */}
        <FullsizeTeamCard
          team={right.team}
          score={right.score}
          possessionTeamId={game.possessionTeamId}
          league={game.league}
          gameStatus={game.gameStatus}
          homeTeam={true}
          showScore={shouldShowGameScore(game.gameStatus)}
          record={right.record}
          timeouts={right.timeouts}
          supportsLiveDetails={leagueSupportsLiveDetails}
        />
      </div>
      {game.lastPlay && (
        <div className="p-2 flex flex-col place-items-center items-center justify-center">
          Last Play:
          <div>{game.lastPlay}</div>
        </div>
      )}
      {game.lastPlay && game.awayWinPercentage && game.homeWinPercentage && (
        <div>
          {game.awayWinPercentage > game.homeWinPercentage ? (
            <div className="p-2 flex flex-col place-items-center items-center justify-center">
              {game.awayTeam.abbreviation} chance to win:
              <div>
                {(Number(game.awayWinPercentage) * 100).toFixed(1) + "%"}
              </div>
            </div>
          ) : (
            <div className="p-2 flex flex-col place-items-center items-center justify-center">
              {game.homeTeam.abbreviation} chance to win:
              <div>
                {(Number(game.homeWinPercentage) * 100).toFixed(1) + "%"}
              </div>
            </div>
          )}
        </div>
      )}
      {scoringPlays.length > 0 && (
        <CollapsableSection
          title={`Scoring Plays`}
          isOpen={isScoringPlaysOpen}
          onToggle={toggleScoringPlays}
        />
      )}
      {isScoringPlaysOpen && (
        <div className="border rounded overflow-hidden divide-y">
          {scoringPlays.map((play) => {
            const hasRunningScore =
              play.homeScore != null && play.awayScore != null;
            return (
              <div className="p-1" key={play.id}>
                <div>
                  {play.period}Q - {play.clock}
                </div>
                <div>
                  {play.teamName} {play.scoringType} - {play.displayText}
                </div>
                {hasRunningScore && (
                  <div>
                    {left.team.abbreviation}{" "}
                    {left.statSide === "homeStats"
                      ? play.homeScore
                      : play.awayScore}{" "}
                    -{" "}
                    {right.statSide === "homeStats"
                      ? play.homeScore
                      : play.awayScore}{" "}
                    {right.team.abbreviation}
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}
      {leaders.size > 0 && (
        <CollapsableSection
          title={`Player Stats`}
          isOpen={isStatsOpen}
          onToggle={toggleStats}
        />
      )}
      {isStatsOpen && (
        <div className="border rounded overflow-hidden divide-y">
          <div className="grid grid-cols-3 text-center divide-x font-semibold">
            <div>{left.team.abbreviation}</div>
            <div>Stat</div>
            <div>{right.team.abbreviation}</div>
          </div>
          {Array.from(leaders.values()).map((leader) => {
            const statName = leader.name;
            if (!statName || renderedStatNames.has(statName)) {
              return null;
            }
            renderedStatNames.add(statName);
            const leftLeader = leaders.get(
              `${statName}-${left.team.teamKey.teamId}`,
            );
            const rightLeader = leaders.get(
              `${statName}-${right.team.teamKey.teamId}`,
            );
            if (!leftLeader && !rightLeader) {
              return null;
            }

            return (
              <div
                key={statName}
                className="grid grid-cols-3 text-center divide-x"
              >
                <div>
                  <div>{leftLeader?.playerShortName}</div>
                  <div>{leftLeader?.displayValue}</div>
                </div>
                <div>
                  {leftLeader?.displayName || rightLeader?.displayName}
                </div>
                <div>
                  <div>{rightLeader?.playerShortName}</div>
                  <div>{rightLeader?.displayValue}</div>
                </div>
              </div>
            );
          })}
        </div>
      )}
      {hasTeamStats && (
        <CollapsableSection
          title={`Team Stats`}
          isOpen={isTeamStatsOpen}
          onToggle={toggleTeamStats}
        />
      )}
      {hasTeamStats && isTeamStatsOpen && (
        <div className="border rounded overflow-hidden divide-y">
          <div className="grid grid-cols-3 text-center divide-x font-semibold">
            <div>{left.team.abbreviation}</div>
            <div>Team Stats</div>
            <div>{right.team.abbreviation}</div>
          </div>
          {Array.from(statsToDisplay.entries()).map(([statKey, statLabel]) => {
            return (
              <div
                className="grid grid-cols-3 text-center divide-x"
                key={statKey + game.id}
              >
                <div>{game.stats?.[left.statSide]?.[statKey]}</div>
                <div>{statLabel}</div>
                <div>{game.stats?.[right.statSide]?.[statKey]}</div>
              </div>
            );
          })}
        </div>
      )}
      <br />
      <div className="flex flex-col place-items-center items-center justify-center">
        {game.headline && <div>{game.headline}</div>}
        {canShowOdds && <div>{game.gameOdd?.spreadText}</div>}
        {shouldShowScheduledOrFinalDate(game.gameStatus) && (
          <div>{dateFormatter.format(new Date(game.isoDate))}</div>
        )}
        <div>{game.stadiumName}</div>
        <div>{game.location}</div>
        {game.espnLink && (
          <div>
            <Link
              href={game.espnLink}
              className="font-medium text-blue-600 dark:text-blue-400 hover:underline"
              target="_blank"
            >
              ESPN
            </Link>
          </div>
        )}
      </div>
    </div>
  );
};

export default FullSizeGameCard;

